css:
.loader {color: var(--loader-color, #f97316);
  --loader-secondary-color: #facc15;
  --loader-bg: #ffffff;
   height: 68px;
   width: 50px;
   border: 8px solid currentColor;
   box-sizing: border-box;
   background: conic-gradient(from 160deg at top,currentColor 40deg,#0000 0) top, conic-gradient(from -20deg at bottom,currentColor 40deg,#0000 0) bottom, radial-gradient(farthest-side,currentColor 98%,#0000) bottom/100% 50%, currentColor;
   background-size:100% 50%;
   background-repeat: no-repeat;
   filter: blur(4px) contrast(10);
   animation: l20 1s infinite alternate;
}
@keyframes l20  {
  0%,30% {background-position:top,bottom,bottom}
70%,100% {background-position:top,bottom,top}
}
